//name: 测试2-DOM与事件
//author: Test
(function() {
    console.log('[测试2] IIFE 执行');

    // 1) 测试DOM - 创建红色方块
    var box = document.createElement('div');
    box.textContent = '测试2方块';
    box.style.cssText = 'position:fixed;right:20px;bottom:20px;z-index:99999;width:60px;height:60px;background:red;color:white;display:flex;align-items:center;justify-content:center;border-radius:8px;cursor:pointer;';
    box.onclick = function() {
        if (typeof toastr !== 'undefined') toastr.info('方块被点击了!', '测试2');
    };
    document.body.appendChild(box);
    console.log('[测试2] DOM元素已添加, document.body存在:', !!document.body);

    // 2) 测试事件监听 - 听酒馆助手按钮点击
    if (typeof window.eventOn === 'function' && window.tavern_events) {
        console.log('[测试2] eventOn 可用, 监听 MESSAGE_RECEIVED');
        window.eventOn(window.tavern_events.MESSAGE_RECEIVED, function() {
            console.log('[测试2] MESSAGE_RECEIVED 事件触发');
        });
    } else {
        console.log('[测试2] eventOn 不可用, typeof:', typeof window.eventOn, 'tavern_events:', typeof window.tavern_events);
    }

    // 3) 测试 iframe_events
    if (window.iframe_events) {
        console.log('[测试2] iframe_events 可用:', Object.keys(window.iframe_events).join(', '));
    } else {
        console.log('[测试2] iframe_events 不存在');
    }

    // 4) 测试 triggerSlash
    if (window.TavernHelper && window.TavernHelper.triggerSlash) {
        console.log('[测试2] triggerSlash 可用');
    } else {
        console.log('[测试2] triggerSlash 不可用');
    }

    toastr.success('测试2: 页面右下角应有红色方块', '酒馆助手测试');
})();
